from typing import Callable
from typing import ClassVar

MutantDict = Annotated[dict[str, Callable], "Mutant"] # type: ignore


def _mutmut_trampoline(orig, mutants, call_args, call_kwargs, self_arg = None): # type: ignore
    """Forward call to original or mutated function, depending on the environment"""
    import os # type: ignore
    mutant_under_test = os.environ['MUTANT_UNDER_TEST'] # type: ignore
    if mutant_under_test == 'fail': # type: ignore
        from mutmut.__main__ import MutmutProgrammaticFailException # type: ignore
        raise MutmutProgrammaticFailException('Failed programmatically')       # type: ignore
    elif mutant_under_test == 'stats': # type: ignore
        from mutmut.__main__ import record_trampoline_hit # type: ignore
        record_trampoline_hit(orig.__module__ + '.' + orig.__name__) # type: ignore
        # (for class methods, orig is bound and thus does not need the explicit self argument)
        result = orig(*call_args, **call_kwargs) # type: ignore
        return result # type: ignore
    prefix = orig.__module__ + '.' + orig.__name__ + '__mutmut_' # type: ignore
    if not mutant_under_test.startswith(prefix): # type: ignore
        result = orig(*call_args, **call_kwargs) # type: ignore
        return result # type: ignore
    mutant_name = mutant_under_test.rpartition('.')[-1] # type: ignore
    if self_arg is not None: # type: ignore
        # call to a class method where self is not bound
        result = mutants[mutant_name](self_arg, *call_args, **call_kwargs) # type: ignore
    else:
        result = mutants[mutant_name](*call_args, **call_kwargs) # type: ignore
    return result # type: ignore


# ============================================================================
# Error Types
# ============================================================================


class FeatureDetectionError(Exception):
    """Base exception for feature detection failures."""
    pass


class MultipleFeaturesError(FeatureDetectionError):
    """Raised when multiple features exist and no context clarifies which."""

    def __init__(self, features: list[str], message: str):
        args = [features, message]# type: ignore
        kwargs = {}# type: ignore
        return _mutmut_trampoline(object.__getattribute__(self, 'xǁMultipleFeaturesErrorǁ__init____mutmut_orig'), object.__getattribute__(self, 'xǁMultipleFeaturesErrorǁ__init____mutmut_mutants'), args, kwargs, self)

    def xǁMultipleFeaturesErrorǁ__init____mutmut_orig(self, features: list[str], message: str):
        super().__init__(message)
        self.features = features

    def xǁMultipleFeaturesErrorǁ__init____mutmut_1(self, features: list[str], message: str):
        super().__init__(None)
        self.features = features

    def xǁMultipleFeaturesErrorǁ__init____mutmut_2(self, features: list[str], message: str):
        super().__init__(message)
        self.features = None
    
    xǁMultipleFeaturesErrorǁ__init____mutmut_mutants : ClassVar[MutantDict] = { # type: ignore
    'xǁMultipleFeaturesErrorǁ__init____mutmut_1': xǁMultipleFeaturesErrorǁ__init____mutmut_1, 
        'xǁMultipleFeaturesErrorǁ__init____mutmut_2': xǁMultipleFeaturesErrorǁ__init____mutmut_2
    }
    xǁMultipleFeaturesErrorǁ__init____mutmut_orig.__name__ = 'xǁMultipleFeaturesErrorǁ__init__'


class NoFeatureFoundError(FeatureDetectionError):
    """Raised when no feature can be detected."""
    pass


# ============================================================================
# Core Types
# ============================================================================


@dataclass
class FeatureContext:
    """Rich result from feature detection.

    Attributes:
        slug: Full feature slug (e.g., "020-my-feature")
        number: Feature number only (e.g., "020")
        name: Feature name only (e.g., "my-feature")
        directory: Path to feature directory (e.g., Path("kitty-specs/020-my-feature"))
        detection_method: How feature was detected (e.g., "git_branch", "env_var", "explicit")
    """
    slug: str
    number: str
    name: str
    directory: Path
    detection_method: str

    @classmethod
    def from_slug(cls, slug: str, repo_root: Path, detection_method: str) -> "FeatureContext":
        """Construct FeatureContext from a feature slug.

        Args:
            slug: Feature slug in format ###-feature-name
            repo_root: Repository root path
            detection_method: How the feature was detected

        Returns:
            FeatureContext instance

        Raises:
            FeatureDetectionError: If slug format is invalid
        """
        match = re.match(r'^(\d{3})-(.+)$', slug)
        if not match:
            raise FeatureDetectionError(
                f"Invalid feature slug format: {slug}\n"
                f"Expected format: ###-feature-name (e.g., 020-my-feature)"
            )

        number = match.group(1)
        name = match.group(2)
        directory = repo_root / "kitty-specs" / slug

        return cls(
            slug=slug,
            number=number,
            name=name,
            directory=directory,
            detection_method=detection_method,
        )


