def _detect_from_git_branch(repo_root: Path) -> Optional[str]:
    args = [repo_root]# type: ignore
    kwargs = {}# type: ignore
    return _mutmut_trampoline(x__detect_from_git_branch__mutmut_orig, x__detect_from_git_branch__mutmut_mutants, args, kwargs, None)


def x__detect_from_git_branch__mutmut_orig(repo_root: Path) -> Optional[str]:
    """Detect feature from git branch name.

    Args:
        repo_root: Repository root path

    Returns:
        Feature slug if detected, None otherwise
    """
    try:
        result = subprocess.run(
            ["git", "rev-parse", "--abbrev-ref", "HEAD"],
            cwd=repo_root,
            capture_output=True,
            text=True,
            encoding="utf-8",
            errors="replace",
            check=True,
        )
        branch = result.stdout.strip()

        # Pattern 1: Worktree branch (###-feature-name-WP##)
        # Check this FIRST - more specific pattern
        # Extract feature slug by removing -WP## suffix
        match = re.match(r'^((\d{3})-.+)-WP\d{2}$', branch)
        if match:
            feature_slug = match.group(1)
            return feature_slug

        # Pattern 2: Feature branch (###-feature-name)
        match = re.match(r'^(\d{3})-.+$', branch)
        if match:
            return branch

    except (subprocess.CalledProcessError, FileNotFoundError):
        pass

    return None


