    cwd = cwd or Path.cwd()

    detected_slug: Optional[str] = None
    detection_method: str = ""

    # Priority 1: Explicit --feature parameter
    if explicit_feature:
        detected_slug = explicit_feature.strip()
        detection_method = "explicit"

